import crypto from "node:crypto";
import { createAgentSession } from "../agentSessionChannel.js";
import { openChromelessWindow } from "../browser.js";
import { getConfig, hasCredentials } from "../config.js";
/**
 * Open the user's most recent trace plan in the browser. Unlike
 * `openTracePlan`, this command does **not** block waiting for confirm/cancel
 * — it routes through the bitfab-web `/trace-plans/latest` redirector, opens
 * the resulting page, and exits. The page server-side resolves the latest
 * plan for the org and redirects to its detail view.
 *
 * A fresh agent session is created and threaded through `?session=` so the
 * `tracePlan:latestOpened` event the page emits lands in the Studio live
 * activity stream for whoever is watching.
 */
export async function runViewLastTracePlan(platform) {
    if (!hasCredentials()) {
        console.error(`Not authenticated. Run ${platform.loginHint} first.`);
        process.exit(1);
    }
    const config = getConfig();
    if (!config.apiKey) {
        console.error("No API key configured.");
        process.exit(1);
    }
    const sessionId = crypto.randomUUID();
    try {
        await createAgentSession({
            serviceUrl: config.serviceUrl,
            apiKey: config.apiKey,
            sessionId,
            extraHeaders: {
                "x-bitfab-client-name": platform.cliBinary,
                "x-bitfab-client-display-name": platform.displayName,
            },
        });
    }
    catch (err) {
        // Session creation is a best-effort signal for Studio. If it fails, we
        // still want the user to land on the plan — open the URL without the
        // session param.
        console.error(`agent session bind failed, opening without session: ${err.message}`);
        openChromelessWindow(`${config.serviceUrl}/trace-plans/latest`);
        process.exit(0);
    }
    const url = `${config.serviceUrl}/trace-plans/latest?session=${encodeURIComponent(sessionId)}`;
    openChromelessWindow(url);
    process.exit(0);
}
